// Gera registros CNAB 240 para Boletos (Segmento J e J-52)
const items = $input.all();
const registros = [];

let sequencial = 1;

// Função para converter linha digitável (47 dígitos) em código de barras (44 dígitos)
function linhaDigitavelParaCodigoBarras(linha) {
  linha = linha.replace(/[\s.]/g, '');

  if (linha.length === 44) {
    return linha;
  }

  if (linha.length === 47) {
    const bancoMoeda = linha.substring(0, 4);      // Pos 1-4
    const campoLivre1 = linha.substring(4, 9);     // Pos 5-9 (5 dígitos)
    // Pos 10 = DV (pular)
    const campoLivre2 = linha.substring(10, 20);   // Pos 11-20 (10 dígitos)
    // Pos 21 = DV (pular)
    const campoLivre3 = linha.substring(21, 31);   // Pos 22-31 (10 dígitos)
    // Pos 32 = DV (pular)
    const dvGeral = linha.substring(32, 33);       // Pos 33 (1 dígito)
    const fatorVenc = linha.substring(33, 37);     // Pos 34-37 (4 dígitos)
    const valor = linha.substring(37, 47);         // Pos 38-47 (10 dígitos)

    return bancoMoeda + dvGeral + fatorVenc + valor + campoLivre1 + campoLivre2 + campoLivre3;
  }

  return linha.padEnd(44, ' ');
}

for (const item of items) {
  const dados = item.json;
  const linhaDigitavel = dados.codigo_barras || '';
  const codigoBarras = linhaDigitavelParaCodigoBarras(linhaDigitavel);
  const valor = Math.round((dados.valor || 0) * 100);

  let vencimentoFormatado = '00000000';
  if (dados.vencimento) {
    const partes = dados.vencimento.split('-');
    if (partes.length === 3) {
      vencimentoFormatado = partes[2] + partes[1] + partes[0];
    }
  }

  const nomeCedente = (dados.nome_cedente_original || '').substring(0, 30).padEnd(30, ' ');

  const hoje = new Date();
  const dataPagamento = String(hoje.getDate()).padStart(2, '0') + 
                        String(hoje.getMonth() + 1).padStart(2, '0') + 
                        String(hoje.getFullYear());

  const segmentoJ = [
    '745',
    '0001',
    '3',
    String(sequencial).padStart(5, '0'),
    'J',
    '0',
    '00',
    codigoBarras,
    nomeCedente,
    vencimentoFormatado,
    String(valor).padStart(15, '0'),
    String(0).padStart(15, '0'),
    String(0).padStart(15, '0'),
    dataPagamento,
    String(valor).padStart(15, '0'),
    String(0).padStart(15, '0'),
    ''.padEnd(20, ' '),
    ''.padEnd(20, ' '),
    '09',
    ''.padEnd(6, ' '),
    ''.padEnd(10, ' ')
  ].join('');

  sequencial++;

  const cnpjBeneficiario = (dados.cnpj_cedente_original || '').replace(/\D/g, '').padStart(14, '0');

  const segmentoJ52 = [
    '745',
    '0001',
    '3',
    String(sequencial).padStart(5, '0'),
    'J',
    ' ',
    '00',
    '52',
    '2',
    '05385049000123'.padStart(15, '0'),
    'AIR CANADA'.padEnd(40, ' '),
    '2',
    cnpjBeneficiario.padStart(15, '0'),
    nomeCedente.padEnd(40, ' '),
    '0',
    ''.padStart(15, '0'),
    ''.padEnd(40, ' '),
    ''.padEnd(53, ' ')
  ].join('');

  sequencial++;

  registros.push({
    id: dados.id,
    tipo: 'boleto',
    linhaDigitavelOriginal: linhaDigitavel,
    codigoBarrasGerado: codigoBarras,
    codigoBarrasLength: codigoBarras.length,
    segmentoJ: segmentoJ,
    segmentoJLength: segmentoJ.length,
    segmentoJ52: segmentoJ52,
    segmentoJ52Length: segmentoJ52.length,
    sequencialFinal: sequencial - 1,
    valor: dados.valor
  });
}

return registros.map(r => ({ json: r }));

// Gera Trailer de Lote para Boletos (Registro Tipo 5)
const dados = $input.first().json;

// Quantidade de registros no lote:
// 1 (header) + registros detalhe (cada boleto = 2: segmento J + J52) + 1 (trailer)
const qtdRegistrosDetalhe = dados.registros.length * 2; // J + J52 por boleto
const qtdTotalLote = 1 + qtdRegistrosDetalhe + 1; // header + detalhes + trailer

// Soma dos valores (em centavos)
const somaValores = Math.round(dados.somaValores * 100);

// Trailer de Lote - Tipo 5 (240 posições)
const trailerLote = [
  '745',                                            // 001-003: Banco Citibank
  '0001',                                           // 004-007: Lote de serviço
  '5',                                              // 008: Tipo de registro (5=Trailer Lote)
  ''.padEnd(9, ' '),                                // 009-017: Brancos FEBRABAN
  String(qtdTotalLote).padStart(6, '0'),            // 018-023: Quantidade de registros no lote
  String(somaValores).padStart(18, '0'),            // 024-041: Somatória dos valores
  ''.padStart(18, '0'),                             // 042-059: Quantidade de moedas (zeros)
  ''.padStart(6, '0'),                              // 060-065: Número aviso débito (zeros)
  ''.padEnd(165, ' '),                              // 066-230: Brancos
  ''.padEnd(10, ' ')                                // 231-240: Ocorrências
].join('');

return [{ 
  json: {
    ...dados,
    trailerLote: trailerLote,
    trailerLoteLength: trailerLote.length,
    qtdTotalLote: qtdTotalLote
  }
}];

// Monta o arquivo CNAB completo com múltiplos lotes
const lotes = $input.all();

// Arrays para armazenar todas as linhas
const linhas = [];
let qtdLotes = 0;
let qtdRegistrosTotal = 0;
const idsProcessados = [];
let valorTotal = 0;

// Data e hora de geração (São Paulo - UTC-3)
const agora = new Date();
const saoPauloOffset = -3 * 60;
const saoPauloTime = new Date(agora.getTime() + (saoPauloOffset - agora.getTimezoneOffset()) * 60000);

const hoje = saoPauloTime;
const dataGeracao = String(hoje.getDate()).padStart(2, '0') + 
                    String(hoje.getMonth() + 1).padStart(2, '0') + 
                    String(hoje.getFullYear());
const horaGeracao = String(hoje.getHours()).padStart(2, '0') + 
                    String(hoje.getMinutes()).padStart(2, '0') + 
                    String(hoje.getSeconds()).padStart(2, '0');

// NSA - Número Sequencial do Arquivo
const nsa = '000000';

// 1. Header de Arquivo (tipo 0)
const headerArquivo = [
  '745',                                            // 001-003: Banco Citibank
  '0000',                                           // 004-007: Lote (0000 para header arquivo)
  '0',                                              // 008: Tipo de registro (0=Header Arquivo)
  ''.padEnd(9, ' '),                                // 009-017: Brancos FEBRABAN
  '2',                                              // 018: Tipo inscrição empresa (2=CNPJ)
  '05385049000123',                                 // 019-032: CNPJ Air Canada (14)
  ''.padEnd(20, ' '),                               // 033-052: Código convênio (20)
  '00001',                                          // 053-057: Agência (5)
  ' ',                                              // 058: Dígito agência (1)
  '000112353011',                                   // 059-070: Conta (12)
  ' ',                                              // 071: Dígito conta (1)
  ' ',                                              // 072: Dígito ag/conta (1)
  'AIR CANADA'.padEnd(30, ' '),                     // 073-102: Nome empresa (30)
  'CITIBANK'.padEnd(30, ' '),                       // 103-132: Nome do banco (30)
  ''.padEnd(10, ' '),                               // 133-142: Brancos FEBRABAN
  '1',                                              // 143: Código remessa (1=Remessa)
  dataGeracao,                                      // 144-151: Data geração (DDMMAAAA)
  horaGeracao,                                      // 152-157: Hora geração (HHMMSS)
  nsa,                                              // 158-163: NSA (6)
  '060',                                            // 164-166: Layout do arquivo
  '00000',                                          // 167-171: Densidade (zeros)
  ''.padEnd(20, ' '),                               // 172-191: Reservado banco
  ''.padEnd(20, ' '),                               // 192-211: Reservado empresa
  ''.padEnd(29, ' ')                                // 212-240: Brancos FEBRABAN
].join('');

linhas.push(headerArquivo);
qtdRegistrosTotal++;

// 2. Processar cada lote (Boleto, TED, Concessionária)
for (const lote of lotes) {
  const dados = lote.json;
  qtdLotes++;

  // Header do Lote
  linhas.push(dados.headerLote);
  qtdRegistrosTotal++;

  // Registros de Detalhe
  for (const registro of dados.registros) {
    // Boleto: Segmento J + J52
    if (registro.tipo === 'boleto') {
      linhas.push(registro.segmentoJ);
      linhas.push(registro.segmentoJ52);
      qtdRegistrosTotal += 2;
    }
    // TED: Segmento A + B
    else if (registro.tipo === 'ted') {
      linhas.push(registro.segmentoA);
      linhas.push(registro.segmentoB);
      qtdRegistrosTotal += 2;
    }
    // Concessionária: Segmento O
    else if (registro.tipo === 'concessionaria') {
      linhas.push(registro.segmentoO);
      qtdRegistrosTotal += 1;
    }

    idsProcessados.push(registro.id);
    valorTotal += registro.valor || 0;
  }

  // Trailer do Lote
  linhas.push(dados.trailerLote);
  qtdRegistrosTotal++;
}

// 3. Trailer de Arquivo (tipo 9)
qtdRegistrosTotal++; // Incluir o próprio trailer na contagem

const trailerArquivo = [
  '745',                                            // 001-003: Banco Citibank
  '9999',                                           // 004-007: Lote (9999 para trailer arquivo)
  '9',                                              // 008: Tipo de registro (9=Trailer Arquivo)
  ''.padEnd(9, ' '),                                // 009-017: Brancos FEBRABAN
  String(qtdLotes).padStart(6, '0'),                // 018-023: Quantidade de lotes
  String(qtdRegistrosTotal).padStart(6, '0'),       // 024-029: Quantidade de registros
  ''.padStart(6, '0'),                              // 030-035: Quantidade de contas (zeros)
  ''.padEnd(205, ' ')                               // 036-240: Brancos
].join('');

linhas.push(trailerArquivo);

// Montar arquivo completo
const arquivoCompleto = linhas.join('\n');

// Gerar nome do arquivo
const horaArquivo = String(hoje.getHours()).padStart(2, '0') + 
                    String(hoje.getMinutes()).padStart(2, '0');
const nomeArquivo = `CNAB240_${dataGeracao}_${horaArquivo}.txt`;

return [{ 
  json: {
    arquivoCompleto: arquivoCompleto,
    nomeArquivo: nomeArquivo,
    qtdLinhas: linhas.length,
    qtdLotes: qtdLotes,
    idsProcessados: idsProcessados,
    valorTotal: valorTotal
  }
}];

// Prepara o arquivo para salvar no Google Drive
const dados = $input.first().json;

// Converte o conteúdo para binário
const conteudo = dados.arquivoCompleto;

// Criar item com binary data
const newItem = {
  json: {
    nomeArquivo: dados.nomeArquivo,
    idsProcessados: dados.idsProcessados,
    valorTotal: dados.valorTotal,
    qtdLinhas: dados.qtdLinhas
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(conteudo, 'utf-8'),
      dados.nomeArquivo,
      'text/plain'
    )
  }
};

return [newItem];

// Salva os dados da conta no item para usar depois
const conta = $json;

return {
  // Dados da conta (prefixados)
  conta_id: conta.id,
  conta_valor: conta.valor,
  conta_vencimento: conta.vencimento,
  conta_descricao: conta.descricao,
  // Passa o fornecedor_id para o próximo nó buscar
  fornecedor_id: conta.fornecedor_id
};

const fornecedores = $input.all();
const contas = $('Preparar_TED').all();
const resultados = [];

for (let i = 0; i < fornecedores.length; i++) {
  const fornecedor = fornecedores[i].json;
  const contaDados = contas[i]?.json || {};

  resultados.push({
    json: {
      conta_id: contaDados.conta_id,
      valor: contaDados.conta_valor,
      vencimento: contaDados.conta_vencimento,
      descricao: contaDados.conta_descricao,
      fornecedor_nome: fornecedor.nome,
      fornecedor_cnpj: fornecedor.cnpj,
      fornecedor_cpf: fornecedor.cpf,
      fornecedor_tipo: fornecedor.tipo,
      fornecedor_banco: fornecedor.banco,
      fornecedor_agencia: fornecedor.agencia,
      fornecedor_conta: fornecedor.conta,
      fornecedor_tipo_conta: fornecedor.tipo_conta
    }
  });
}

return resultados;

// Gera registros CNAB 240 para TED (Segmento A e B)
const items = $input.all();
const registros = [];

let sequencial = 1;

for (const item of items) {
  const dados = item.json;

  const valor = Math.round((dados.valor || 0) * 100);

  let dataPagamento = '00000000';
  if (dados.vencimento) {
    const partes = dados.vencimento.split('-');
    if (partes.length === 3) {
      dataPagamento = partes[2] + partes[1] + partes[0];
    }
  }

  // Dados do fornecedor
  const bancoFavorecido = (dados.fornecedor_banco || '').padStart(3, '0');

  // Agência: remover não numéricos, 5 posições
  const agenciaLimpa = (dados.fornecedor_agencia || '').replace(/\D/g, '');
  const agencia = agenciaLimpa.padStart(5, '0');
  const agenciaDigito = ' '; // Se não tiver dígito separado

  // Conta: separar número e dígito
  const contaOriginal = (dados.fornecedor_conta || '');
  let contaNumero = '';
  let contaDigito = ' ';

  if (contaOriginal.includes('-')) {
    const partesConta = contaOriginal.split('-');
    contaNumero = partesConta[0].replace(/\D/g, '').padStart(12, '0');
    contaDigito = partesConta[1] || ' ';
  } else {
    contaNumero = contaOriginal.replace(/\D/g, '').padStart(12, '0');
  }

  // Nome em MAIÚSCULO
  const nomeFavorecido = (dados.fornecedor_nome || '').toUpperCase().substring(0, 30).padEnd(30, ' ');

  // Tipo de inscrição: 1=CPF, 2=CNPJ
  const tipoInscricao = dados.fornecedor_tipo === 'pf' ? '1' : '2';
  const inscricao = (dados.fornecedor_cnpj || dados.fornecedor_cpf || '').replace(/\D/g, '').padStart(14, '0');

  // Seu número (identificador)
  const seuNumero = ''.padEnd(20, ' ');

  // Segmento A - Layout correto conforme arquivo válido
  const segmentoA = [
    '745',                                            // 001-003: Banco Citibank
    '0002',                                           // 004-007: Lote
    '3',                                              // 008: Tipo registro
    String(sequencial).padStart(5, '0'),              // 009-013: Sequencial
    'A',                                              // 014: Segmento
    '0',                                              // 015: Tipo movimento
    '00',                                             // 016-017: Código instrução
    '018',                                            // 018-020: Câmara (018=TED)
    bancoFavorecido,                                  // 021-023: Banco favorecido (3)
    agencia,                                          // 024-028: Agência (5)
    agenciaDigito,                                    // 029: Dígito agência (1)
    contaNumero,                                      // 030-041: Conta (12)
    contaDigito,                                      // 042: Dígito conta (1)
    ' ',                                              // 043: Dígito ag/conta (1)
    nomeFavorecido,                                   // 044-073: Nome favorecido (30)
    seuNumero,                                        // 074-093: Seu número (20)
    dataPagamento,                                    // 094-101: Data pagamento (8)
    'BRL',                                            // 102-104: Moeda (3)
    ''.padStart(15, '0'),                             // 105-119: Quantidade moeda (15)
    String(valor).padStart(15, '0'),                  // 120-134: Valor pagamento (15)
    ''.padEnd(20, ' '),                               // 135-154: Nosso número (20)
    ''.padStart(15, '0'),                             // 155-169: Zeros (15)
    ''.padEnd(5, ' '),                                // 170-174: Brancos (5)
    ''.padEnd(5, '0'),                                // 175-179: Zeros (5)
    ''.padEnd(5, ' '),                                // 180-184: Brancos (5)
    ''.padEnd(1, ' '),                                // 185: Branco (1)
    ''.padEnd(44, ' '),                               // 186-229: Brancos (44)
    '0'.padEnd(10, ' ')                               // 230-240: Ocorrências (10) - ajustar se necessário
  ].join('');

  sequencial++;

  // Segmento B permanece igual
  const segmentoB = [
    '745',
    '0002',
    '3',
    String(sequencial).padStart(5, '0'),
    'B',
    '   ',
    tipoInscricao,
    inscricao,
    ''.padEnd(30, ' '),
    ''.padEnd(5, ' '),
    ''.padEnd(15, ' '),
    ''.padEnd(15, ' '),
    ''.padEnd(20, ' '),
    ''.padEnd(8, ' '),
    ''.padEnd(2, ' '),
    dataPagamento,
    String(valor).padStart(15, '0'),
    ''.padStart(15, '0'),
    ''.padStart(15, '0'),
    ''.padStart(15, '0'),
    ''.padStart(15, '0'),
    ''.padEnd(15, ' '),
    ''.padStart(7, '0'),
    ''.padEnd(8, ' ')
  ].join('');

  sequencial++;

  registros.push({
    id: dados.conta_id,
    tipo: 'ted',
    segmentoA: segmentoA,
    segmentoB: segmentoB,
    segmentoALength: segmentoA.length,
    segmentoBLength: segmentoB.length,
    sequencialFinal: sequencial - 1,
    valor: dados.valor
  });
}

return registros.map(r => ({ json: r }));

// Gera Trailer de Lote para TED (Registro Tipo 5)
const dados = $input.first().json;

// Quantidade de registros no lote:
// 1 (header) + registros detalhe (cada TED = 2: segmento A + B) + 1 (trailer)
const qtdRegistrosDetalhe = dados.registros.length * 2; // A + B por TED
const qtdTotalLote = 1 + qtdRegistrosDetalhe + 1; // header + detalhes + trailer

// Soma dos valores (em centavos)
const somaValores = Math.round(dados.somaValores * 100);

// Trailer de Lote TED - Tipo 5 (240 posições)
const trailerLote = [
  '745',                                            // 001-003: Banco Citibank
  '0002',                                           // 004-007: Lote de serviço (0002 para TED)
  '5',                                              // 008: Tipo de registro (5=Trailer Lote)
  ''.padEnd(9, ' '),                                // 009-017: Brancos FEBRABAN
  String(qtdTotalLote).padStart(6, '0'),            // 018-023: Quantidade de registros no lote
  String(somaValores).padStart(18, '0'),            // 024-041: Somatória dos valores
  ''.padStart(18, '0'),                             // 042-059: Quantidade de moedas (zeros)
  ''.padStart(6, '0'),                              // 060-065: Número aviso débito (zeros)
  ''.padEnd(165, ' '),                              // 066-230: Brancos
  ''.padEnd(10, ' ')                                // 231-240: Ocorrências
].join('');

return [{ 
  json: {
    ...dados,
    trailerLote: trailerLote,
    trailerLoteLength: trailerLote.length,
    qtdTotalLote: qtdTotalLote
  }
}];

// Pega os IDs do nó Criar_Arquivo_CNAB
const ids = $('Criar_Arquivo_CNAB').first().json.idsProcessados;

// Retorna cada ID como um item separado
return ids.map(id => ({ json: { id: id } }));

// Gera registros CNAB 240 para Concessionárias (Segmento O)
const items = $input.all();
const registros = [];

let sequencial = 1;

for (const item of items) {
  const dados = item.json;

  const valor = Math.round((dados.valor || 0) * 100); // Em centavos

  // Código de barras de concessionária tem 44 ou 48 dígitos
  let codigoBarrasOriginal = (dados.codigo_barras || '').replace(/[\s.-]/g, '');
  let codigoBarras = codigoBarrasOriginal;

  // Se for 48 dígitos (linha digitável de convênio), converter para 44 (código de barras)
  if (codigoBarras.length === 48) {
    // Remove os dígitos verificadores nas posições 12, 24, 36, 48 (índices 11, 23, 35, 47)
    const parte1 = codigoBarras.substring(0, 11);   // posições 1-11 (11 chars)
    const parte2 = codigoBarras.substring(12, 23);  // posições 13-23 (11 chars)
    const parte3 = codigoBarras.substring(24, 35);  // posições 25-35 (11 chars)
    const parte4 = codigoBarras.substring(36, 47);  // posições 37-47 (11 chars)
    codigoBarras = parte1 + parte2 + parte3 + parte4;
  }

  // Garantir 44 posições
  codigoBarras = codigoBarras.substring(0, 44).padEnd(44, ' ');

  // Formatar vencimento: de YYYY-MM-DD para DDMMAAAA
  let vencimentoFormatado = '00000000';
  if (dados.vencimento) {
    const partes = dados.vencimento.split('-');
    if (partes.length === 3) {
      vencimentoFormatado = partes[2] + partes[1] + partes[0]; // DDMMAAAA
    }
  }

  // Data de pagamento = hoje (São Paulo)
  const agora = new Date();
  const saoPauloOffset = -3 * 60;
  const saoPauloTime = new Date(agora.getTime() + (saoPauloOffset - agora.getTimezoneOffset()) * 60000);
  const dataPagamento = String(saoPauloTime.getDate()).padStart(2, '0') + 
                        String(saoPauloTime.getMonth() + 1).padStart(2, '0') + 
                        String(saoPauloTime.getFullYear());

  const nomeConcessionaria = (dados.nome_cedente_original || '').substring(0, 30).padEnd(30, ' ');

  // Segmento O - Pagamento de Concessionárias (240 posições)
  const segmentoO = [
    '745',                                            // 001-003: Banco Citibank
    '0003',                                           // 004-007: Lote (0003 para Concessionária)
    '3',                                              // 008: Tipo registro (detalhe)
    String(sequencial).padStart(5, '0'),              // 009-013: Sequencial
    'O',                                              // 014: Segmento
    '0',                                              // 015: Tipo movimento (0=Inclusão)
    '00',                                             // 016-017: Código instrução
    codigoBarras,                                     // 018-061: Código de barras (44)
    nomeConcessionaria,                               // 062-091: Nome concessionária (30)
    vencimentoFormatado,                              // 092-099: Data vencimento (8)
    dataPagamento,                                    // 100-107: Data pagamento (8)
    String(valor).padStart(15, '0'),                  // 108-122: Valor pagamento (15)
    ''.padEnd(20, ' '),                               // 123-142: Seu número (20)
    ''.padEnd(20, ' '),                               // 143-162: Nosso número (20)
    ''.padEnd(68, ' '),                               // 163-230: Brancos (68)
    ''.padEnd(10, ' ')                                // 231-240: Ocorrências (10)
  ].join('');

